package org.apache.commons.math.optimization;

import org.apache.commons.math.FunctionEvaluationException;
import org.apache.commons.math.analysis.UnivariateRealFunction;
import org.apache.commons.math.random.JDKRandomGenerator;
import org.junit.Test;
import static org.junit.Assert.*;

public class ReproductionTest {

    @Test
    public void testNaNHandling() throws Exception {
        UnivariateRealOptimizer mockOptimizer = new UnivariateRealOptimizer() {
            private int count = 0;
            public double optimize(UnivariateRealFunction f, GoalType goalType, double min, double max, double startValue) {
                return optimize(f, goalType, min, max);
            }
            public double optimize(UnivariateRealFunction f, GoalType goalType, double min, double max) throws FunctionEvaluationException {
                count++;
                if (count == 1) {
                    throw new FunctionEvaluationException(0); // Trigger NaN for first run
                }
                return 0.0; // Return valid for others
            }
            // Boilerplate
            public double getFunctionValue() { return 0.0; }
            public double getResult() { return 0.0; }
            public double getAbsoluteAccuracy() { return 0.0; }
            public int getIterationCount() { return 0; }
            public int getMaximalIterationCount() { return 0; }
            public int getMaxEvaluations() { return 0; }
            public int getEvaluations() { return 0; }
            public double getRelativeAccuracy() { return 0.0; }
            public void resetAbsoluteAccuracy() {}
            public void resetMaximalIterationCount() {}
            public void resetRelativeAccuracy() {}
            public void setAbsoluteAccuracy(double accuracy) {}
            public void setMaximalIterationCount(int count) {}
            public void setMaxEvaluations(int maxEvaluations) {}
            public void setRelativeAccuracy(double accuracy) {}
        };

        MultiStartUnivariateRealOptimizer optimizer = new MultiStartUnivariateRealOptimizer(mockOptimizer, 5, new JDKRandomGenerator());

        try {
            optimizer.optimize(new UnivariateRealFunction() {
                public double value(double x) { return x; }
            }, GoalType.MINIMIZE, -1, 1);
            fail("Should have thrown Exception or handled it, but let's see");
        } catch (ArrayIndexOutOfBoundsException e) {
            // Expected bug
            System.out.println("Caught expected AIOOBE: " + e.getMessage());
            return;
        } catch (Exception e) {
             System.out.println("Caught unexpected exception: " + e);
             throw e;
        }

        fail("Should have crashed with AIOOBE due to bug");
    }
}

